import{_ as a,c as t,o as i,ag as o}from"./chunks/framework.DPDPlp3K.js";const r="/assets/architecture.MhFPdavm.svg",g=JSON.parse('{"title":"Modular Architecture","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/architecture.html"}]]},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),s={name:"architecture.md"};function n(l,e,c,p,h,u){return i(),t("div",null,e[0]||(e[0]=[o('<h1 id="modular-architecture" tabindex="-1">Modular Architecture <a class="header-anchor" href="#modular-architecture" aria-label="Permalink to &quot;Modular Architecture&quot;">​</a></h1><p>SQLRooms is designed with a modular architecture that allows developers to pick and choose exactly the functionality they need for their data analytics applications. This approach enables you to build custom solutions tailored to your specific requirements.</p><p><img src="'+r+'" alt="SQLRooms Architecture"></p><h2 id="core-philosophy" tabindex="-1">Core Philosophy <a class="header-anchor" href="#core-philosophy" aria-label="Permalink to &quot;Core Philosophy&quot;">​</a></h2><p>The SQLRooms architecture follows these key principles:</p><ol><li><strong>Modularity</strong>: Each package has a specific, focused purpose</li><li><strong>Composability</strong>: Packages can be combined in various ways to create custom applications</li><li><strong>Minimal Dependencies</strong>: Packages only depend on what they absolutely need</li><li><strong>Consistent API Design</strong>: All packages follow similar patterns for ease of use</li><li><a href="/state-management.html"><strong>Slice-Based State Management</strong></a>: State management uses a composable slice pattern that allows applications to combine functionality from different modules</li></ol><h2 id="core-components" tabindex="-1">Core Components <a class="header-anchor" href="#core-components" aria-label="Permalink to &quot;Core Components&quot;">​</a></h2><h3 id="projectstore" tabindex="-1">ProjectStore <a class="header-anchor" href="#projectstore" aria-label="Permalink to &quot;ProjectStore&quot;">​</a></h3><p>The central state management system built on Zustand handles:</p><ul><li>Project configuration and persistence</li><li>Data source management</li><li>DuckDB integration</li><li>Type-safe state management</li></ul><p>The ProjectStore can be extended with custom configuration and functionality specific to your needs.</p><h3 id="project-builder" tabindex="-1">Project Builder <a class="header-anchor" href="#project-builder" aria-label="Permalink to &quot;Project Builder&quot;">​</a></h3><p>Provides the application shell with:</p><ul><li>Configurable and pluggable views</li><li>Flexible panel layouts</li><li>Sidebar and main view management</li></ul><h3 id="built-in-views" tabindex="-1">Built-in Views <a class="header-anchor" href="#built-in-views" aria-label="Permalink to &quot;Built-in Views&quot;">​</a></h3><p>Ready-to-use components accelerate development:</p><ul><li>DataTable View for displaying and interacting with query results</li><li>S3 Browser for managing data sources and importing data</li><li>SQL Query Editor with syntax highlighting</li></ul><h2 id="package-structure" tabindex="-1">Package Structure <a class="header-anchor" href="#package-structure" aria-label="Permalink to &quot;Package Structure&quot;">​</a></h2><p>SQLRooms is organized into several categories of packages:</p><h3 id="core-packages" tabindex="-1">Core Packages <a class="header-anchor" href="#core-packages" aria-label="Permalink to &quot;Core Packages&quot;">​</a></h3><p>These packages form the foundation of any SQLRooms application:</p><ul><li><p><strong><a href="https://sqlrooms.github.io/api/project-builder/" target="_blank" rel="noreferrer">@sqlrooms/project-builder</a></strong>: The central package that provides the foundation for building analytics applications with Zustand-based state management. It handles project state management using a composable slice-based architecture, allowing applications to combine and extend functionality from different modules. The package integrates the panel system and includes DuckDB integration to keep track of database tables created as part of the project.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/project-config/" target="_blank" rel="noreferrer">@sqlrooms/project-config</a></strong>: Defines central configuration and type definitions using Zod schemas. It provides TypeScript types and interfaces along with essential constants and utilities used throughout the framework.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/duckdb/" target="_blank" rel="noreferrer">@sqlrooms/duckdb</a></strong>: Provides DuckDB integration for query execution and data source connections. It manages DuckDB-WASM instances and handles query execution with robust data source connection capabilities and ensures type-safe query results for reliable data operations.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/ui/" target="_blank" rel="noreferrer">@sqlrooms/ui</a></strong>: Offers a comprehensive UI toolkit based on shadcn/ui with Tailwind preset. It includes a carefully crafted Tailwind preset configuration, a library of common UI components, robust theme management capabilities, and a collection of icons and assets.</p></li></ul><h3 id="feature-packages" tabindex="-1">Feature Packages <a class="header-anchor" href="#feature-packages" aria-label="Permalink to &quot;Feature Packages&quot;">​</a></h3><p>These packages provide specific functionality that can be added as needed:</p><ul><li><p><strong><a href="https://sqlrooms.github.io/api/data-table/" target="_blank" rel="noreferrer">@sqlrooms/data-table</a></strong>: An advanced interactive data grid component designed for SQL query result visualization. The table supports dynamic column sorting and pagination features for efficient data exploration and analysis.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/sql-editor/" target="_blank" rel="noreferrer">@sqlrooms/sql-editor</a></strong>: A powerful SQL query editor that enhances the development experience with syntax highlighting and intelligent auto-completion. It maintains a query history for easy reference and provides integrated result visualization capabilities.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/layout/" target="_blank" rel="noreferrer">@sqlrooms/layout</a></strong>: A sophisticated layout system and panel management solution based on <a href="https://nomcopter.github.io/react-mosaic/" target="_blank" rel="noreferrer">react-mosaic</a> that enables flexible panel layouts with intuitive sidebar and main view management. It supports smooth panel resize functionality and ensures layout persistence across sessions.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/s3-browser/" target="_blank" rel="noreferrer">@sqlrooms/s3-browser</a></strong>: A feature-rich S3-compatible storage browser that provides an intuitive file browsing interface. It supports file upload and download operations, comprehensive directory management, and seamless S3 bucket integration.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/vega/" target="_blank" rel="noreferrer">@sqlrooms/vega</a></strong>: A data visualization package that integrates <a href="https://vega.github.io/vega-lite/" target="_blank" rel="noreferrer">Vega-Lite</a> for creating sophisticated interactive visualizations. It provides React components for rendering Vega specifications and handling visualization interactions.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/ai/" target="_blank" rel="noreferrer">@sqlrooms/ai</a></strong>: An AI integration package that enables natural language querying and analysis capabilities. It provides tools for query generation, result interpretation, and interactive AI-powered analytics workflows.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/cosmos/" target="_blank" rel="noreferrer">@sqlrooms/cosmos</a></strong>: A graph visualization package that integrates <a href="https://github.com/cosmograph-org/cosmos" target="_blank" rel="noreferrer">Cosmos</a> for creating interactive network visualizations. It provides high-performance WebGL-based graph rendering capabilities with support for large-scale networks.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/dropzone/" target="_blank" rel="noreferrer">@sqlrooms/dropzone</a></strong>: A comprehensive file upload solution that implements drag-and-drop functionality. It provides sophisticated file upload handling with built-in file type validation and upload progress tracking to enhance the user experience.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/mosaic/" target="_blank" rel="noreferrer">@sqlrooms/mosaic</a></strong>: A visualization package that integrates with <a href="https://idl.uw.edu/mosaic/" target="_blank" rel="noreferrer">UW Interactive Data Lab&#39;s Mosaic library</a>. It provides declarative chart specifications and interactive visualization capabilities for data analysis.</p></li><li><p><strong><a href="https://sqlrooms.github.io/api/monaco-editor/" target="_blank" rel="noreferrer">@sqlrooms/monaco-editor</a></strong>: A powerful code editing package that integrates <a href="https://microsoft.github.io/monaco-editor/" target="_blank" rel="noreferrer">Monaco Editor</a> (the editor that powers VS Code). It provides customizable text editing components with features like syntax highlighting, code completion, and theming. The package includes specialized editors for JSON with schema validation support.</p></li></ul><h3 id="utility-packages" tabindex="-1">Utility Packages <a class="header-anchor" href="#utility-packages" aria-label="Permalink to &quot;Utility Packages&quot;">​</a></h3><ul><li><strong><a href="https://sqlrooms.github.io/api/utils/" target="_blank" rel="noreferrer">@sqlrooms/utils</a></strong>: A utility package providing shared helper functions for color manipulation, data formatting, random generation, and string operations used across the framework.</li><li><strong><a href="https://sqlrooms.github.io/api/typescript-config/" target="_blank" rel="noreferrer">@sqlrooms/typescript-config</a></strong>: Shared TypeScript configuration</li><li><strong><a href="https://sqlrooms.github.io/api/eslint-config/" target="_blank" rel="noreferrer">@sqlrooms/eslint-config</a></strong>: Shared ESLint configuration</li><li><strong><a href="https://sqlrooms.github.io/api/typedoc-config/" target="_blank" rel="noreferrer">@sqlrooms/typedoc-config</a></strong>: Shared TypeDoc configuration</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><p>The framework is designed to be highly extensible through:</p><ol><li><p><strong>Extended ProjectStore</strong></p><ul><li>Custom project configuration using Zod schemas</li><li>Additional state management</li><li>Integration with other services</li></ul></li><li><p><strong>Custom Views and Panels</strong></p><ul><li>Create specialized views for specific use cases</li><li>Configure panel layouts and behavior</li><li>Integrate with existing panel management</li></ul></li></ol><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><ol><li>Data sources (CSV, Parquet) are loaded through the dropzone, the S3 browser or custom import methods</li><li>DuckDB processes queries locally in the browser</li><li>Results are displayed in the DataTable view or custom visualizations</li><li>Project state can be saved and loaded for persistence</li></ol><p>This extensibility allows you to customize the behavior of each slice to meet your specific requirements.</p><h1 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h1><p>SQLRooms&#39; modular architecture gives you the flexibility to build exactly the data analytics application you need. By combining different packages and slices, you can create anything from simple data explorers to complex AI-powered analytics dashboards, all running entirely in the browser.</p><p>The <a href="/state-management.html">slice-based state management</a> makes it easy to pick and choose the functionality you need while maintaining a clean and organized codebase. This approach allows for maximum flexibility and extensibility, enabling you to create custom solutions tailored to your specific requirements.</p>',36)]))}const m=a(s,[["render",n]]);export{g as __pageData,m as default};
